import Foundation

/// Bundled Arabic copy when API rows omit `arabic_*` (e.g. Supabase seed without `*_arabic` migrations, or older Express DB).
/// Keys match catalog `name` + `city` for activities; season events key by `name` (VUZ uses Unicode en dash \u{2013}).
enum PublicListingArabicFallback {

    struct ActivityStrings {
        let title: String
        let category: String
        let location: String
        let description: String
    }

    /// Activity Arabic when `arabicName` / server fields are empty.
    static func activityStrings(name: String, city: String) -> ActivityStrings? {
        activityTable["\(name)|\(city)"]
    }

    /// Safety / liability line(s) for activity detail (Figma **1449:9860** — e.g. Scuba, Desert Safari, Moon Hike).
    static func activitySafetyGuidelines(name: String, city: String, isArabic: Bool) -> String? {
        guard let pair = activitySafetyTable["\(name)|\(city)"] else { return nil }
        return isArabic ? pair.ar : pair.en
    }

    /// Season event Arabic when server fields are empty.
    static func seasonEventStrings(name: String) -> (title: String, category: String, location: String)? {
        seasonEventTable[name]
    }

